----自动集结设置保存请求，全量数据
function LxGuildAssemblyHandler:GuildAssembleAutomaticUpdateReq()
    local info = ModuleCenter.GuildAssembly:GetAutomaticInfo()

    local proto = LxProtoHelper.CreateProto(LxProtoIds.GuildAssembleAutomaticUpdateReq)
    local automaticObj = proto.automaticObj
    automaticObj.autoFormation = info.autoFormation

    if info.defineFormation ~= nil and info.defineFormation.heroIds ~= nil and not table.isempty(info.defineFormation.heroIds) and info.defineFormation.soldierMap ~= nil and not table.isempty(info.defineFormation.soldierMap) then
        automaticObj.defineFormation["formationIndex"] = info.defineFormation.formationIndex

        for _, id in pairs(info.defineFormation.heroIds) do
            table.insert(automaticObj.defineFormation["heroIds"], id)
        end

        local soldierMap = automaticObj.defineFormation["soldiers"]
        for _, v in pairs(info.defineFormation.soldierMap) do
            local kv = soldierMap:add()
            kv.key = v.key
            kv.value = v.value
        end
    end

    for id, state in pairs(info.refIds) do
        if state == true then
            table.insert(automaticObj.refIds, id)
        end
    end

    automaticObj.offlineAutoJoin = info.offlineAutoJoin
    automaticObj.hurtPercent = info.hurtPercent

    SendMessage(LxProtoIds.GuildAssembleAutomaticUpdateReq, proto)
end

