---公会集结信息,登录推送
function LxGuildAssemblyHandler:OnGuildAssembleListResp(pb)
    ModuleCenter.GuildAssembly:ClearAllGuildAssemblyInfo()
    ModuleCenter.GuildAssembly:SetAssemblyDataList(pb.atkAssembles, GuildAssemblyType.Attack)
    ModuleCenter.GuildAssembly:SetAssemblyDataList(pb.defAssembles, GuildAssemblyType.Defence)
    ModuleCenter.GuildAssembly:SetSingleWarList(pb.singleWars)
    ModuleCenter.GuildAssembly:SetFollowRoleIds(pb.followRoleIds)
    ModuleCenter.GuildAssembly:SetAutomaticInfo(pb.automaticObj)
    FireEvent(EventNames.GUILD_ASSEMBLY_ALL_INFO_REFRESH)
end

---集结信息更新通知,如果停留在集结页面,刷新信息（GuildAssembleUpdateListReq）
function LxGuildAssemblyHandler:OnGuildAssembleUpdateResp(pb)
    if not IsOpenPanel(UiNames.GuildAssemblyMain) then
        return
    end

    --更新类型：1刷新集结信息；2清空集结信息；3行军销毁（只删除即可）
    if pb.updateType == 1 then
        self:GuildAssembleUpdateListReq(pb.dataType)
        if IsOpenPanel(UiNames.GuildAssemblyDetail) and pb.updateMarchIds ~= nil and not table.isempty(pb.updateMarchIds) then
            local isReq = false
            for i, id in ipairs(pb.updateMarchIds) do
                if id == self.curSpeedMarchId then
                    self:GuildAssembleDetailReq(id)
                    self.curSpeedMarchId = nil
                    isReq = true
                end
            end

            if isReq == false then
                FireEvent(EventNames.GUILD_ASSEMBLY_DETAIL_REFRESH_ID_LIST, pb.updateMarchIds)
            end
        end
    elseif pb.updateType == 2 then
        if pb.dataType == nil or pb.dataType == 0 then
            ModuleCenter.GuildAssembly:ClearAllGuildAssemblyInfo()
        elseif pb.dataType == 1 or pb.dataType == 2 then
            ModuleCenter.GuildAssembly:ClearGuildAssemblyByType()
        elseif pb.dataType == 3 then
            ModuleCenter.GuildAssembly:ClearSingleWarList()
        end
        FireEvent(EventNames.GUILD_ASSEMBLY_ALL_INFO_REFRESH)
    elseif pb.updateType == 3 then
        if pb.updateMarchIds ~= nil and not table.isempty(pb.updateMarchIds) then
            for i, id in ipairs(pb.updateMarchIds) do
                ModuleCenter.GuildAssembly:DeleteAssemblyInfoById(id)
            end
        end
        FireEvent(EventNames.GUILD_ASSEMBLY_ALL_INFO_REFRESH)
    end
end

