---请求数据类型：0返回全部列表数据；1集结攻击；2集结防守；3单人作战
function LxGuildAssemblyHandler:OnGuildAssembleUpdateListResp(pb)
    local type = pb.type
    if type == 0 then
        ModuleCenter.GuildAssembly:SetAssemblyDataList(pb.atkAssembles, GuildAssemblyType.Attack)
        ModuleCenter.GuildAssembly:SetAssemblyDataList(pb.defAssembles, GuildAssemblyType.Defence)
        ModuleCenter.GuildAssembly:SetSingleWarList(pb.singleWars)
    elseif type == GuildAssemblyType.Attack then
        ModuleCenter.GuildAssembly:SetAssemblyDataList(pb.atkAssembles, GuildAssemblyType.Attack)
    elseif type == GuildAssemblyType.Defence then
        ModuleCenter.GuildAssembly:SetAssemblyDataList(pb.defAssembles, GuildAssemblyType.Defence)
    elseif type == GuildAssemblyType.Single then
        ModuleCenter.GuildAssembly:SetSingleWarList(pb.singleWars)
    end
    FireEvent(EventNames.GUILD_ASSEMBLY_ALL_INFO_REFRESH)
end

return LxGuildAssemblyHandler